import org.jfree.chart.JFreeChart;
import org.jfree.chart.plot.MultiplePiePlot;
import org.jfree.chart.plot.PiePlot;
import org.jfree.chart.title.TextTitle;
import java.awt.*;

public class MultiPiePlot extends MultiplePiePlot{

    public MultiPiePlot(CategoryDataset dataset){
        super();
        super.initialize();
        super.setIgnoreNullValues(true);
        super.setBaseSectionOutlinePaint(Color.WHITE);

        ((MultiPiePlot)this).addDomainTitle("Sub Category");

        //Removing legend from all plots except the first one.
        for(int i = 0 ; i < getPlotCount() ;i++){

            //Adding title on top of plot.

            String temp ="Title "+String.valueOf((char)(65+i));

            System.out.println(temp );
            super.getPlot(i).setForegroundPaint(Color.white);
            super.getPlot(i).addTextNote(1 , 1, "hi how r u ",new Rectangle(1,1,2,2),null );
            ((MultiPiePlot)this).getPlot(i).removeLegend();

        }

     // Setting dataset for all the plots.
      super.setDataset(dataset);
    }
}

